messages.content:
Analyze the following JSON PRD and design resource access interfaces.

JSON PRD:
```json
{
  "metadata": {
    "project_name": "Project Task Manager",
    "project_id": "com.example.project-task-manager",
    "version": "1.0.0"
  },
  "functional_requirements": [
    {
      "fr_id": "FR-001",
      "title": "Create Project",
      "description": "Create a new project with name, description, owner_id. Check owner exists. Default status planning. Record creation time.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": []
    },
    {
      "fr_id": "FR-002",
      "title": "Update Project",
      "description": "Update project info: description, owner_id, status, deadline. Check project exists. Record status changes.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-003",
      "title": "Delete Project",
      "description": "Delete project and all its tasks. Check project exists.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-004",
      "title": "Create Task",
      "description": "Create task with project_id, title, description, priority, estimated_hours. Check project exists and status is planning or active. Default status todo. No assignee.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001"
      ]
    },
    {
      "fr_id": "FR-005",
      "title": "Assign Task",
      "description": "Assign task to a member. Check task exists and unassigned or reassignable. Check member exists and available. Optionally check skills. Update assignee_id and member status to busy.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-004"
      ]
    },
    {
      "fr_id": "FR-006",
      "title": "Update Task Status",
      "description": "Update task status. Check task exists. Status flow: todo->in_progress->review->done. Blocked can be set anytime. Record actual_hours when done.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-004"
      ]
    },
    {
      "fr_id": "FR-007",
      "title": "Complete Task",
      "description": "Complete a task from review to done. Record actual_hours. Release member (set available).",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-006"
      ]
    },
    {
      "fr_id": "FR-008",
      "title": "Delete Task",
      "description": "Delete a task. Check task exists. If assigned, release member.",
      "priority": "high",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-004"
      ]
    },
    {
      "fr_id": "FR-009",
      "title": "List Project Tasks",
      "description": "List tasks for a project with optional filters: status, priority, assignee. Show task details and progress.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-004"
      ]
    },
    {
      "fr_id": "FR-010",
      "title": "Get Member Tasks",
      "description": "Get all tasks for a member: current and historical. Calculate total hours.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-005"
      ]
    },
    {
      "fr_id": "FR-011",
      "title": "Get Project Progress",
      "description": "Get project progress: completion rate, task counts by status, estimated vs actual hours, estimated completion time.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-001",
        "FR-004"
      ]
    },
    {
      "fr_id": "FR-012",
      "title": "Add Member",
      "description": "Add a new team member. Check member_id uniqueness.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": []
    },
    {
      "fr_id": "FR-013",
      "title": "Update Member Availability",
      "description": "Update member availability. Can only set to offline if no active tasks.",
      "priority": "medium",
      "related_nfr_ids": [],
      "depends_on": [
        "FR-005"
      ]
    }
  ],
  "non_functional_requirements": [
    {
      "nfr_id": "NFR-001",
      "category": "reliability",
      "description": "Data consistency across three data sources must be maintained."
    },
    {
      "nfr_id": "NFR-002",
      "category": "usability",
      "description": "Error handling for invalid project/task/member and status conflicts."
    }
  ],
  "acceptance_criteria": [
    {
      "ac_id": "AC-001",
      "description": "Create project with valid owner returns success with project_id and status planning.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-001"
      ]
    },
    {
      "ac_id": "AC-002",
      "description": "Create project with invalid owner returns failure.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-001"
      ]
    },
    {
      "ac_id": "AC-003",
      "description": "Update project status to active sets deadline correctly.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-002"
      ]
    },
    {
      "ac_id": "AC-004",
      "description": "Delete project removes project and all its tasks.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-003"
      ]
    },
    {
      "ac_id": "AC-005",
      "description": "Create task in active project returns task with status todo.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-004"
      ]
    },
    {
      "ac_id": "AC-006",
      "description": "Assign task to available member updates assignee and member status to busy.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-005"
      ]
    },
    {
      "ac_id": "AC-007",
      "description": "Assign task to busy member returns failure.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-005"
      ]
    },
    {
      "ac_id": "AC-008",
      "description": "Update task status from todo to in_progress succeeds.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-006"
      ]
    },
    {
      "ac_id": "AC-009",
      "description": "Complete task from review sets status done and releases member.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-007"
      ]
    },
    {
      "ac_id": "AC-010",
      "description": "Delete task releases member if assigned.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-008"
      ]
    },
    {
      "ac_id": "AC-011",
      "description": "List project tasks with status filter returns correct tasks.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-009"
      ]
    },
    {
      "ac_id": "AC-012",
      "description": "Get member tasks returns current and completed tasks with total hours.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-010"
      ]
    },
    {
      "ac_id": "AC-013",
      "description": "Get project progress returns correct completion rate and hours.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-011"
      ]
    },
    {
      "ac_id": "AC-014",
      "description": "Add member with unique ID succeeds.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-012"
      ]
    },
    {
      "ac_id": "AC-015",
      "description": "Update member availability to offline fails if member has active tasks.",
      "verification_method": "automated_test",
      "related_fr_ids": [
        "FR-013"
      ]
    }
  ],
  "technical_constraints": {
    "storage": {
      "type": "memory",
      "details": "Three independent in-memory data sources: members, projects, tasks."
    },
    "concurrency": {
      "model": "single-user",
      "auth_required": false
    },
    "ui": {
      "type": "api"
    },
    "language": "Python"
  },
  "glossary": {
    "member": "A team member with role, skills, and availability.",
    "project": "A project with tasks, owner, and status.",
    "task": "A task within a project with assignee, status, priority, and hours.",
    "status flow": "The allowed transitions of task status: todo -> in_progress -> review -> done; blocked can be set anytime."
  },
  "global_state_sources": [
    {
      "source_id": "members",
      "type": "list",
      "description": "Stores team member information.",
      "initial_state": [
        {
          "member_id": 1,
          "name": "张开发",
          "role": "developer",
          "skills": [
            "python",
            "javascript"
          ],
          "availability": "available"
        },
        {
          "member_id": 2,
          "name": "李设计",
          "role": "designer",
          "skills": [
            "ui",
            "css"
          ],
          "availability": "available"
        },
        {
          "member_id": 3,
          "name": "王测试",
          "role": "tester",
          "skills": [
            "testing",
            "automation"
          ],
          "availability": "available"
        },
        {
          "member_id": 4,
          "name": "赵前端",
          "role": "developer",
          "skills": [
            "javascript",
            "react"
          ],
          "availability": "available"
        },
        {
          "member_id": 5,
          "name": "陈后端",
          "role": "developer",
          "skills": [
            "python",
            "database"
          ],
          "availability": "available"
        },
        {
          "member_id": 6,
          "name": "刘经理",
          "role": "manager",
          "skills": [
            "planning",
            "coordination"
          ],
          "availability": "available"
        }
      ],
      "item_schema": {
        "member_id": "integer",
        "name": "string",
        "role": "string (developer|designer|tester|manager)",
        "skills": "list of strings",
        "availability": "string (available|busy|offline)"
      }
    },
    {
      "source_id": "projects",
      "type": "list",
      "description": "Stores project information.",
      "initial_state": [],
      "item_schema": {
        "project_id": "integer",
        "name": "string",
        "description": "string",
        "owner_id": "integer",
        "status": "string (planning|active|completed|cancelled)",
        "created_at": "datetime",
        "deadline": "datetime (optional)"
      }
    },
    {
      "source_id": "tasks",
      "type": "list",
      "description": "Stores task records.",
      "initial_state": [],
      "item_schema": {
        "task_id": "integer",
        "project_id": "integer",
        "title": "string",
        "description": "string",
        "assignee_id": "integer (optional)",
        "status": "string (todo|in_progress|review|done|blocked)",
        "priority": "string (low|medium|high|critical)",
        "estimated_hours": "number",
        "actual_hours": "number (optional)",
        "created_at": "datetime"
      }
    }
  ],
  "input_spec": {
    "format": "json",
    "description": "Input is a JSON object with command and project_data fields. The command specifies the operation, and project_data contains the parameters.",
    "schema": {
      "command": "string (one of: create_project, update_project, delete_project, create_task, assign_task, update_task_status, complete_task, delete_task, list_project_tasks, get_member_tasks, get_project_progress, add_member, update_member_availability)",
      "project_data": "object containing relevant fields for the command"
    },
    "examples": [
      {
        "command": "create_project",
        "project_data": {
          "name": "网站重构",
          "description": "重构公司官网",
          "owner_id": 6
        }
      }
    ]
  },
  "output_spec": {
    "format": "json",
    "description": "Output is a JSON object with success, message, and data fields.",
    "schema": {
      "success": "boolean",
      "message": "string",
      "data": "object (varies by command)"
    },
    "examples": [
      {
        "success": true,
        "message": "项目创建成功",
        "data": {
          "project_id": 1,
          "status": "planning"
        }
      }
    ]
  }
}
```

Remember:
- Choose storage model from: dict, list, in_memory_table
- Choose operations from: get, list, create, update, delete, exists
- Do NOT create business action interfaces like pay_order or ship_order
- Create only low-level CRUD interfaces
- Every resource needs at least a get interface
